<?php\n// Define time zones to display\n$timezones = [\n    'America/New_York' => 'New York (EST)',\n    'Europe/London' => 'London (GMT)',\n    'Europe/Paris' => 'Paris (CET)',\n    'Asia/Dubai' => 'Dubai (GST)',\n    'Asia/Tokyo' => 'Tokyo (JST)',\n    'Asia/Hong_Kong' => 'Hong Kong (HKT)',\n    'Australia/Sydney' => 'Sydney (AEDT)',\n    'Asia/Kolkata' => 'India (IST)',\n];\n?>\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Digital Clock - Multiple Time Zones</title>\n    <link rel=\"stylesheet\" href=\"css/clock-style.css\">\n</head>\n<body>\n    <div class=\"clock-container\">\n        <div class=\"header\">\n            <h1>🕐 World Clock</h1>\n            <p>Current Time in Different Time Zones</p>\n        </div>\n\n        <div class=\"clock-grid\">\n            <?php foreach ($timezones as $timezone => $label): ?>\n                <div class=\"clock-card\">\n                    <div class=\"timezone-label\"><?php echo $label; ?></div>\n                    <div class=\"clock-display\" id=\"clock-<?php echo str_replace('/', '-', $timezone); ?>\" data-timezone=\"<?php echo $timezone; ?>\">\n                        <span class=\"time\">--:--:--</span>\n                    </div>\n                    <div class=\"date-display\" id=\"date-<?php echo str_replace('/', '-', $timezone); ?>\"></div>\n                </div>\n            <?php endforeach; ?>\n        </div>\n\n        <div class=\"controls\">\n            <button id=\"toggleFormat\" class=\"btn-toggle\">12-Hour Format</button>\n            <button id=\"toggleSeconds\" class=\"btn-toggle\">Hide Seconds</button>\n        </div>\n    </div>\n\n    <script>\n        // Clock functionality\n        const timezones = <?php echo json_encode($timezones); ?>;\n        let is24Hour = true;\n        let showSeconds = true;\n\n        function formatTime(date, is24Hour, showSeconds) {\n            let hours = date.getHours();\n            const minutes = String(date.getMinutes()).padStart(2, '0');\n            const seconds = String(date.getSeconds()).padStart(2, '0');\n\n            if (!is24Hour) {\n                const period = hours >= 12 ? 'PM' : 'AM';\n                hours = hours % 12 || 12;\n                if (showSeconds) {\n                    return `${String(hours).padStart(2, '0')}:${minutes}:${seconds} ${period}`;\n                } else {\n                    return `${String(hours).padStart(2, '0')}:${minutes} ${period}`;\n                }\n            } else {\n                if (showSeconds) {\n                    return `${String(hours).padStart(2, '0')}:${minutes}:${seconds}`;\n                } else {\n                    return `${String(hours).padStart(2, '0')}:${minutes}`;\n                }\n            }\n        }\n\n        function formatDate(date) {\n            const options = { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' };\n            return date.toLocaleDateString('en-US', options);\n        }\n\n        function updateClocks() {\n            Object.keys(timezones).forEach(timezone => {\n                const date = new Date(new Date().toLocaleString('en-US', { timeZone: timezone }));\n                const timeString = formatTime(date, is24Hour, showSeconds);\n                const dateString = formatDate(date);\n\n                const clockId = `clock-${timezone.replace('/', '-')}`;\n                const dateId = `date-${timezone.replace('/', '-')}`;\n\n                const clockElement = document.getElementById(clockId);\n                const dateElement = document.getElementById(dateId);\n\n                if (clockElement) {\n                    clockElement.querySelector('.time').textContent = timeString;\n                }\n                if (dateElement) {\n                    dateElement.textContent = dateString;\n                }\n            });\n        }\n\n        // Toggle time format\n        document.getElementById('toggleFormat').addEventListener('click', function() {\n            is24Hour = !is24Hour;\n            this.textContent = is24Hour ? '12-Hour Format' : '24-Hour Format';\n            updateClocks();\n        });\n\n        // Toggle seconds display\n        document.getElementById('toggleSeconds').addEventListener('click', function() {\n            showSeconds = !showSeconds;\n            this.textContent = showSeconds ? 'Hide Seconds' : 'Show Seconds';\n            updateClocks();\n        });\n\n        // Update clocks every second\n        updateClocks();\n        setInterval(updateClocks, 1000);\n    </script>\n</body>\n</html>"